// Deterministic parenting-tips selector. Replaces the parenting_tips slice
// of the dashboard AI prompt (was generated by getParentDashboardPrompt and
// returned by generateParentDashboardInsights).
//
// Selection model
// ---------------
// Each tip carries a list of "signals". A signal fires when the student's
// current data crosses a threshold (low attendance, weak average, pending
// homework backlog, upcoming tests, etc.). Tips matching the active signals
// are ranked by signal-priority, then by stable hash of tip text so the
// list stays stable across renders for the same data.
//
// We always reserve at least one slot for an evergreen tip (sleep / reading)
// so a student with perfect data still sees actionable guidance.

export type ParentingTip = { tip: string; reason: string };

type Signal =
  | "attendance_low"      // < 75
  | "attendance_mid"      // 75..84
  | "attendance_high"     // >= 85
  | "score_low"           // 1..59
  | "score_mid"           // 60..79
  | "score_high"          // >= 80
  | "pending_heavy"       // > 3
  | "pending_some"        // 1..3
  | "pending_clear"       // 0
  | "tests_upcoming"      // > 0
  | "grade_primary"       // 1..5
  | "grade_middle"        // 6..8
  | "grade_senior"        // 9..12
  | "evergreen";          // always eligible

type CuratedTip = ParentingTip & {
  signals: Signal[];
  priority: number;       // higher wins ties
};

export type ParentingTipInput = {
  attendance: number | null;
  avgScore: number;       // 0 if unknown
  pending: number | null;
  tests: number | null;
  childName: string;
  grade?: string | number | null;
};

const N = (name: string) => (name && name.trim().length > 0 ? name.trim() : "your child");

