const collectSignals = (input: ParentingTipInput): Set<Signal> => {
  const sigs = new Set<Signal>(["evergreen"]);

  if (input.attendance !== null) {
    if (input.attendance < 75) sigs.add("attendance_low");
    else if (input.attendance < 85) sigs.add("attendance_mid");
    else sigs.add("attendance_high");
  }

  if (input.avgScore > 0) {
    if (input.avgScore < 60) sigs.add("score_low");
    else if (input.avgScore < 80) sigs.add("score_mid");
    else sigs.add("score_high");
  }

  if (input.pending !== null) {
    if (input.pending > 3) sigs.add("pending_heavy");
    else if (input.pending >= 1) sigs.add("pending_some");
    else sigs.add("pending_clear");
  }

  if ((input.tests ?? 0) > 0) sigs.add("tests_upcoming");

  const gradeNum = typeof input.grade === "number"
    ? input.grade
    : parseInt(String(input.grade ?? "").replace(/\D+/g, ""), 10);
  if (Number.isFinite(gradeNum) && gradeNum > 0) {
    if (gradeNum <= 5) sigs.add("grade_primary");
    else if (gradeNum <= 8) sigs.add("grade_middle");
    else sigs.add("grade_senior");
  }

  return sigs;
};

const personaliseTip = (tip: string, name: string): string => {
  // Insert the child's name where it reads naturally; otherwise leave alone.
  if (tip.includes("the strong attendance habit")) return `Acknowledge ${name}'s strong attendance habit out loud this week`;
  if (tip.includes("Sit together tonight")) return `Sit with ${name} tonight and list every pending assignment with due dates`;
  if (tip.includes("Sit with the school office")) return `Sit with the school office to plan make-up notes for ${name}'s missed lessons`;
  if (tip.includes("revision block daily")) return `Schedule a focused 30-minute revision block for ${name} daily, same time slot`;
  if (tip.includes("Run a mock test at home")) return `Run a mock test for ${name} at home over the weekend`;
  if (tip.includes("Read aloud together")) return `Read aloud with ${name} for 15 minutes every evening`;
  if (tip.includes("Praise the clean homework")) return `Praise ${name}'s clean homework slate at dinner tonight`;
  return tip;
};

export function selectParentingTips(input: ParentingTipInput, count = 3): ParentingTip[] {
  const name = N(input.childName);
  const signals = collectSignals(input);

  const eligible = TIPS
    .filter((t) => t.signals.some((s) => signals.has(s)))
    .map((t) => ({ ...t, score: t.priority }));

  // Stable secondary sort: hash of tip text, so a tie in priority still
  // produces a deterministic order and the list doesn't reshuffle on every
  // render for the same input.
  const hash = (s: string): number => {
    let h = 0;
    for (let i = 0; i < s.length; i++) h = ((h << 5) - h + s.charCodeAt(i)) | 0;
    return h;
  };

  eligible.sort((a, b) => (b.score - a.score) || (hash(a.tip) - hash(b.tip)));

  // Diversity pass — avoid emitting two tips that both fire on the same
  // top signal (e.g. two attendance_low tips back-to-back). We pick the
  // highest-priority tip per signal first, then top up from the pool.
  const picked: CuratedTip[] = [];
  const usedPrimary = new Set<Signal>();

  for (const t of eligible) {
    if (picked.length >= count) break;
    const primary = t.signals.find((s) => signals.has(s) && s !== "evergreen") ?? "evergreen";
    if (usedPrimary.has(primary) && primary !== "evergreen") continue;
    picked.push(t);
    usedPrimary.add(primary);
  }

  // If still under count, top up ignoring the diversity rule.
  if (picked.length < count) {
    for (const t of eligible) {
      if (picked.length >= count) break;
      if (!picked.includes(t)) picked.push(t);
    }
  }

  return picked.slice(0, count).map((t) => ({
    tip: personaliseTip(t.tip, name),
    reason: t.reason,
  }));
}
